 85→
 86→    /// Append a batch of events inside a single redb write transaction.
 87→    /// Returns the last assigned sequence number.
 88→    fn append_batch_blocking(
 89→        db: &Database,
 90→        events: Vec<EventEnvelope>,
 91→    ) -> LagoResult<(SeqNo, Vec<EventNotification>)> {
 92→        let txn = db
 93→            .begin_write()
 94→            .map_err(|e| LagoError::Journal(format!("begin_write failed: {e}")))?;
 95→
 96→        let mut last_seq = 0u64;
 97→        let mut notifications = Vec::with_capacity(events.len());
 98→        let mut branch_heads_cache: HashMap<Vec<u8>, SeqNo> = HashMap::new();
 99→
100→        {
101→            let mut events_table = txn
102→                .open_table(EVENTS)
103→                .map_err(|e| LagoError::Journal(format!("open events table: {e}")))?;
104→            let mut index_table = txn
105→                .open_table(EVENT_INDEX)
106→                .map_err(|e| LagoError::Journal(format!("open event_index table: {e}")))?;
107→            let mut heads_table = txn
108→                .open_table(BRANCH_HEADS)
109→                .map_err(|e| LagoError::Journal(format!("open branch_heads table: {e}")))?;
110→
111→            for event in &events {
112→                let session_str = event.session_id.as_str();
113→                let branch_str = event.branch_id.as_str();
114→                let branch_key = encode_branch_key(session_str, branch_str);
115→                let current_head = if let Some(cached) = branch_heads_cache.get(&branch_key) {
116→                    *cached
117→                } else {
118→                    let head = heads_table
119→                        .get(branch_key.as_slice())
120→                        .map_err(|e| LagoError::Journal(format!("get branch head: {e}")))?
121→                        .map(|v| v.value())
122→                        .unwrap_or(0);
123→                    branch_heads_cache.insert(branch_key.clone(), head);
124→                    head
125→                };
126→                let assigned_seq = current_head.saturating_add(1);
127→                branch_heads_cache.insert(branch_key.clone(), assigned_seq);
128→
129→                let mut assigned_event = event.clone();
130→                assigned_event.seq = assigned_seq;
131→                // Serialize event to JSON
132→                let json = serde_json::to_string(&assigned_event)?;
133→
134→                // Encode compound key
135→                let event_key = encode_event_key(session_str, branch_str, assigned_seq);
136→
137→                // Write to events table
138→                events_table
139→                    .insert(event_key.as_slice(), json.as_str())
140→                    .map_err(|e| LagoError::Journal(format!("insert event: {e}")))?;
141→
142→                // Write to event index
143→                index_table
144→                    .insert(assigned_event.event_id.as_str(), event_key.as_slice())
145→                    .map_err(|e| LagoError::Journal(format!("insert event index: {e}")))?;
146→
147→                // Update branch head
148→                heads_table
149→                    .insert(branch_key.as_slice(), assigned_seq)
150→                    .map_err(|e| LagoError::Journal(format!("update branch head: {e}")))?;
151→
152→                last_seq = assigned_seq;
153→
154→                notifications.push(EventNotification {
155→                    session_id: assigned_event.session_id.clone(),
156→                    branch_id: assigned_event.branch_id.clone(),
157→                    seq: assigned_seq,
158→                });
159→            }
160→        }
161→
162→        txn.commit()
163→            .map_err(|e| LagoError::Journal(format!("commit failed: {e}")))?;
164→
165→        Ok((last_seq, notifications))
166→    }
