 55→/// Server hostname or IP.
 56→pub const SERVER_ADDRESS: &str = "server.address";
 57→
 58→/// Server port number.
 59→pub const SERVER_PORT: &str = "server.port";
 60→
 61→// ─── Life Agent OS Attributes (life.* namespace) ─────────────────────────────
 62→
 63→/// Agent OS session ID.
 64→pub const LIFE_SESSION_ID: &str = "life.session_id";
 65→
 66→/// Agent OS run ID (within a session).
 67→pub const LIFE_RUN_ID: &str = "life.run_id";
 68→
 69→/// Agent OS branch ID.
 70→pub const LIFE_BRANCH_ID: &str = "life.branch_id";
 71→
 72→/// Current loop phase (perceive, deliberate, gate, execute, commit, reflect, sleep).
 73→pub const LIFE_LOOP_PHASE: &str = "life.loop_phase";
 74→
 75→/// Current operating mode (explore, execute, verify, recover, ask_human, sleep).
 76→pub const LIFE_OPERATING_MODE: &str = "life.operating_mode";
 77→
 78→/// Event sequence number within a session.
 79→pub const LIFE_EVENT_SEQ: &str = "life.event_seq";
 80→
 81→/// Event kind discriminant (e.g. "tool_call_requested", "assistant_text_delta").
 82→pub const LIFE_EVENT_KIND: &str = "life.event_kind";
 83→
 84→/// Remaining token budget.
 85→pub const LIFE_BUDGET_TOKENS: &str = "life.budget.tokens_remaining";
 86→
 87→/// Remaining cost budget (USD).
 88→pub const LIFE_BUDGET_COST: &str = "life.budget.cost_remaining_usd";
 89→
 90→/// Remaining time budget (ms).
 91→pub const LIFE_BUDGET_TIME: &str = "life.budget.time_remaining_ms";
