    let rx = self.notify_tx.subscribe();
    Box::pin(
        async move {
            let tail = EventTailStream::new(db, rx, session_id, branch_id, after_seq);
            Ok(Box::pin(tail) as EventStream)
        }
        .instrument(span),
    )
}

